const patientMap = Object.fromEntries(patientSeed.map((patient) => [patient.id, patient]));
const doctorMap = Object.fromEntries(doctorSeed.map((doctor) => [doctor.doctorId, doctor]));
const invoiceMap = billingSeed.reduce((acc, invoice) => {
  if (!acc[invoice.patientId]) acc[invoice.patientId] = [];
  acc[invoice.patientId].push(invoice);
  return acc;
}, {});
const appointmentMap = appointmentSeed.reduce((acc, appointment) => {
  if (!acc[appointment.patientId]) acc[appointment.patientId] = [];
  acc[appointment.patientId].push(appointment);
  return acc;
}, {});

export const doctors = doctorSeed.map((doctor) => ({
  ...doctor,
  assignedPatients: patientSeed
    .filter((patient) => patient.doctorId === doctor.doctorId)
    .map((patient) => ({ id: patient.id, name: patient.name, status: patient.status, ward: patient.ward })),
  appointmentHistory: appointmentSeed
    .filter((appointment) => appointment.doctorId === doctor.doctorId)
    .map((appointment) => ({
      id: appointment.appointmentId, patient: appointment.patient, date: appointment.date,
      time: appointment.time, status: appointment.status, type: appointment.type,
    })),
}));

export const patients = patientSeed.map((patient, index) => {
  const patientAppointments = appointmentMap[patient.id] || [];
  const patientBilling = invoiceMap[patient.id] || [];
  const departmentKey = patient.department.toLowerCase().replace(/\s+/g, '');
  const doctor = doctorMap[patient.doctorId];
  return {
    ...patient,
    personalDetails: {
      fullName: patient.name, age: patient.age, gender: patient.gender, bloodType: patient.bloodType,
      address: `${index + 12}, Harmony Residency, Bengaluru`, email: patient.email, mobile: patient.mobile,
    },
    admissionHistory: [
      { date: patient.admittedDate, summary: `Admitted to ${patient.ward} under ${patient.department}.`, status: patient.status },
      { date: '2026-04-18', summary: 'Initial triage and diagnostic workup completed.', status: 'Closed' },
    ],
    previousTreatments: [
      { title: `${patient.department} observation plan`, outcome: 'Stable response to treatment', date: '2026-04-20' },
      { title: 'Medication review', outcome: 'Dosage adjusted', date: '2026-05-03' },
    ],
    labReports: (labTemplates[patient.department] || labTemplates.Cardiology).map((report, labIndex) => ({
      id: `${patient.id}-LAB-${labIndex + 1}`, name: report, date: `2026-05-${String(8 + labIndex).padStart(2, '0')}`, status: 'Available',
    })),
    prescriptions: (prescriptionTemplates[departmentKey] || prescriptionTemplates.default).map((prescription, prescriptionIndex) => ({
      id: `${patient.id}-RX-${prescriptionIndex + 1}`, patient: patient.name,
      startDate: `2026-05-${String(6 + prescriptionIndex).padStart(2, '0')}`,
      endDate: `2026-06-${String(6 + prescriptionIndex).padStart(2, '0')}`, ...prescription,
    })),
    diagnosisHistory: (diagnosisTemplates[patient.department] || diagnosisTemplates.Cardiology).map((diagnosis, diagnosisIndex) => ({
      id: `${patient.id}-DX-${diagnosisIndex + 1}`, diagnosis, date: `2026-05-${String(4 + diagnosisIndex).padStart(2, '0')}`, doctor: patient.doctor,
    })),
    insuranceDetails: {
      provider: patient.insuranceProvider, policyNumber: patient.insurancePolicy,
      coverage: patient.insuranceProvider === 'Self Pay' ? 'Not covered' : '80% inpatient coverage',
    },
    assignedDoctor: {
      id: patient.doctorId, name: patient.doctor, department: patient.department,
      specialization: doctor?.specialization || 'General Medicine', phone: doctor?.phone || 'N/A', email: doctor?.email || 'N/A',
    },
    billingHistory: patientBilling,
    upcomingAppointments: patientAppointments.filter((appointment) => ['Pending', 'Confirmed'].includes(appointment.status)),
    previousAppointments: patientAppointments.filter((appointment) => ['Completed', 'Rejected'].includes(appointment.status)),
    surgeryHistory: [
      { id: `${patient.id}-SX-1`, name: `${patient.department} review procedure`, date: '2026-03-11', outcome: 'Recovered well' },
    ],
    vitalsTimeline: [
      { date: 'Mon', heartRate: 72 + index, bloodPressure: 118 + (index % 10), temperature: 98.2, oxygen: 98 },
      { date: 'Tue', heartRate: 74 + index, bloodPressure: 120 + (index % 10), temperature: 98.4, oxygen: 97 },
      { date: 'Wed', heartRate: 73 + index, bloodPressure: 119 + (index % 10), temperature: 98.6, oxygen: 98 },
      { date: 'Thu', heartRate: 71 + index, bloodPressure: 117 + (index % 10), temperature: 98.5, oxygen: 99 },
    ],
    scanReports: (scanTemplates[patient.department] || []).map((scan, scanIndex) => ({
      id: `${patient.id}-SCAN-${scanIndex + 1}`, name: scan, date: `2026-05-${String(2 + scanIndex).padStart(2, '0')}`, status: 'Uploaded',
    })),
    dischargeSummary: patient.status === 'Discharged' ? 'Patient discharged with stable vitals and follow-up advice.' : 'Discharge summary will be generated after treating physician clearance.',
  };
});

export const appointments = appointmentSeed.map((appointment) => {
  const patient = patientMap[appointment.patientId];
  const doctor = doctorMap[appointment.doctorId];
  const billingSummary = (invoiceMap[appointment.patientId] || []).reduce(
    (summary, invoice) => { summary.total += invoice.amount; if (invoice.status === 'Pending') summary.pending += invoice.amount; return summary; },
    { total: 0, pending: 0 },
  );
  return {
    ...appointment,
    department: appointment.department || patient?.department || doctor?.department,
    doctorSpecialization: doctor?.specialization || 'General',
    patientFullName: patient?.name || appointment.patient,
    doctorFullName: doctor?.name || appointment.doctor,
    patientStatus: patient?.status || 'Active',
    contactDetails: { phone: appointment.contactPhone || patient?.phone || 'N/A', email: appointment.contactEmail || patient?.email || 'N/A' },
    previousAppointmentHistory: (appointmentMap[appointment.patientId] || [])
      .filter((entry) => entry.id !== appointment.id)
      .map((entry) => ({ id: entry.appointmentId, date: entry.date, time: entry.time, status: entry.status, doctor: entry.doctor })),
    prescriptionHistory: patients.find((entry) => entry.id === appointment.patientId)?.prescriptions.slice(0, 3) || [],
    billingSummary: { totalBilled: billingSummary.total, pendingAmount: billingSummary.pending, invoiceCount: (invoiceMap[appointment.patientId] || []).length },
  };
});

